/**
 * Form Assignment Lookup - Firebase Firestore Integration
 * 
 * This queries Firebase to find the correct form assignment.
 * Priority: Product-specific > Store-default
 * 
 * REQUIRED: Set up Firebase credentials in n8n:
 * 1. Create a Firebase service account JSON
 * 2. Add it as n8n credential (type: Firebase Admin)
 * 3. Reference it in this code node
 */

const admin = require('firebase-admin');

// Initialize Firebase if not already done
if (!admin.apps.length) {
  // Get credentials from n8n credential store
  // You'll need to configure this in n8n Settings > Credentials
  const serviceAccount = $credentials.firebase;

  admin.initializeApp({
    credential: admin.credential.cert(serviceAccount),
    projectId: serviceAccount.project_id
  });
}

const db = admin.firestore();

const domain = $input.first().json.domain;
const productId = $input.first().json.productId;
const productHandle = $input.first().json.productHandle;

let assignment = null;
let formConfig = null;
let storeInfo = null;

try {
  // First, find the store by domain
  const storesSnapshot = await db.collection('stores')
    .where('url', '==', domain)
    .where('status', '==', 'connected')
    .limit(1)
    .get();

  if (storesSnapshot.empty) {
    // Try with myshopify.com suffix
    const altSnapshot = await db.collection('stores')
      .where('url', '==', domain.replace('.myshopify.com', ''))
      .where('status', '==', 'connected')
      .limit(1)
      .get();

    if (!altSnapshot.empty) {
      storeInfo = { id: altSnapshot.docs[0].id, ...altSnapshot.docs[0].data() };
    }
  } else {
    storeInfo = { id: storesSnapshot.docs[0].id, ...storesSnapshot.docs[0].data() };
  }

  if (!storeInfo) {
    return [{ json: { error: 'Store not found', domain } }];
  }

  // Try to find product-specific assignment first
  if (productId || productHandle) {
    let productQuery = db.collection('assignments')
      .where('storeId', '==', storeInfo.id)
      .where('assignmentType', '==', 'product')
      .where('isActive', '==', true);

    if (productId) {
      productQuery = productQuery.where('productId', '==', productId);
    } else if (productHandle) {
      productQuery = productQuery.where('productHandle', '==', productHandle);
    }

    const productAssignments = await productQuery.limit(1).get();

    if (!productAssignments.empty) {
      assignment = { id: productAssignments.docs[0].id, ...productAssignments.docs[0].data() };
    }
  }

  // Fall back to store-level assignment
  if (!assignment) {
    const storeAssignments = await db.collection('assignments')
      .where('storeId', '==', storeInfo.id)
      .where('assignmentType', '==', 'store')
      .where('isActive', '==', true)
      .orderBy('priority', 'desc')
      .limit(1)
      .get();

    if (!storeAssignments.empty) {
      assignment = { id: storeAssignments.docs[0].id, ...storeAssignments.docs[0].data() };
    }
  }

  if (!assignment) {
    return [{ json: { error: 'No form assignment found', domain, storeId: storeInfo.id } }];
  }

  // Get the form config
  const formDoc = await db.collection('forms').doc(assignment.formId).get();

  if (!formDoc.exists) {
    return [{ json: { error: 'Form not found', formId: assignment.formId } }];
  }

  const formData = formDoc.data();
  formConfig = formData.config;

  // Return the complete response
  const response = {
    formId: assignment.formId,
    formName: formData.name,
    assignment: {
      id: assignment.id,
      type: assignment.assignmentType,
      storeId: assignment.storeId,
      shopifyDomain: domain,
      productId: assignment.productId || null,
      productHandle: assignment.productHandle || null,
      priority: assignment.priority,
      createdAt: assignment.createdAt
    },
    store: {
      id: storeInfo.id,
      name: storeInfo.name,
      domain: domain,
      platform: storeInfo.platform,
      loaderInstalled: storeInfo.loaderInstalled || false
    },
    config: formConfig
  };

  return [{ json: response }];

} catch (error) {
  console.error('Firebase lookup error:', error);
  return [{ json: { error: error.message, domain } }];
}
